for src in src_01KVSB50CJCYAJNW2DPR422TD9 src_01KVSC92E11YFHB65GGTEEBB3S; do
  echo SRC=$src;
  aws s3 cp s3://bkk-election-images-prod/api-data/score/messages/$src/manifest.json - || true; echo;
  aws s3 cp s3://bkk-election-images-prod/api-data/score/messages/$src/draft_latest.json - || true; echo;
  for f in draft_r1.json draft_r2.json draft_r3.json approval_r1.json approval_r2.json approval_r3.json; do
    echo FILE=$f;
    aws s3 cp s3://bkk-election-images-prod/api-data/score/messages/$src/$f - || true; echo;
  done;
 done'
